function solve(c: number, connections: number[][], queries: number[][]): number[] {

  // Implement DSU

  class DSU {
    parent: number[];
    rank: number[];
    constructor(c: number) {
      this.parent = Array(c + 1).fill(0).map((_, i) => i);
      this.rank = Array(c + 1).fill(0);
    }
    find(x: number): number {
      if (this.parent[x] !== x) {
        this.parent[x] = this.find(this.parent[x]);
      }
      return this.parent[x];
    }
    union(x: number, y: number): boolean {
      const xRoot = this.find(x);
      const yRoot = this.find(y);
      if (xRoot === yRoot) return false;
      if (this.rank[xRoot] < this.rank[yRoot]) {
        this.parent[xRoot] = yRoot;
      } else {
        this.parent[yRoot] = xRoot;
        if (this.rank[xRoot] === this.rank[yRoot]) {
          this.rank[xRoot]++;
        }
      }
      return true;
    }
  }

  const dsu = new DSU(c);

  for (const [u, v] of connections) {
    dsu.union(u, v);
  }

  // Now group the stations by their root

  const componentHeaps: Map<number, MinHeap> = new Map();

  const online: boolean[] = new Array(c + 1).fill(true);

  // For each station, find its root, and add to the component.

  for (let i = 1; i <= c; i++) {
    const root = dsu.find(i);
    if (!componentHeaps.has(root)) {
      componentHeaps.set(root, new MinHeap());
    }
    componentHeaps.get(root)!.push(i);
  }

  // Now, process the queries

  const result: number[] = [];

  for (const [queryType, x] of queries) {
    if (queryType === 1) {
      if (online[x]) {
        result.push(x);
      } else {
        const root = dsu.find(x);
        const heap = componentHeaps.get(root);
        if (!heap) {
          result.push(-1);
          continue;
        }
        // Now, process the heap
        while (heap.heap.length > 0) {
          const top = heap.peek();
          if (online[top]) {
            result.push(top);
            break;
          } else {
            heap.pop();
          }
        }
        if (heap.heap.length === 0) {
          result.push(-1);
        }
      }
    } else {
      // type 2: offline
      online[x] = false;
    }
  }

  return result;
}

